const express = require('express');
const https = require('https');
const fs = require('fs');
const path = require('path');

// Load server certificate, private key, and CA certificate for client validation
const serverOptions = {
  // Server's certificate and private key
  key: fs.readFileSync(path.join(__dirname, 'certs', 'server-key.pem')),
  cert: fs.readFileSync(path.join(__dirname, 'certs', 'server-cert.pem')),

  // CA certificate to validate client certificates (for mTLS)
  ca: fs.readFileSync(path.join(__dirname, 'certs', 'ca-cert.pem')),

  // CRITICAL: Request and require client certificates
  requestCert: true,
  rejectUnauthorized: true, // NEVER set to false in production

  // Use only TLS 1.2 and 1.3 (disable older protocols)
  minVersion: 'TLSv1.2',
  maxVersion: 'TLSv1.3',

  // Strong cipher suites only (AEAD ciphers preferred)
  ciphers: [
    'TLS_AES_256_GCM_SHA384',
    'TLS_AES_128_GCM_SHA256',
    'TLS_CHACHA20_POLY1305_SHA256',
    'ECDHE-RSA-AES256-GCM-SHA384',
    'ECDHE-RSA-AES128-GCM-SHA256'
  ].join(':'),

  // Enable OCSP stapling for certificate revocation checking
  honorCipherOrder: true,

  // Security headers
  secureOptions: require('constants').SSL_OP_NO_TLSv1 | require('constants').SSL_OP_NO_TLSv1_1
};

const app = express();

// Middleware to validate client certificate
app.use((req, res, next) => {
  const cert = req.socket.getPeerCertificate();

  if (!req.client.authorized) {
    return res.status(401).json({
      error: 'Invalid client certificate',
      reason: req.socket.authorizationError
    });
  }

  // Additional certificate validation
  if (!cert || !cert.subject) {
    return res.status(401).json({ error: 'No client certificate provided' });
  }

  // Validate certificate common name (CN)
  const allowedCNs = ['api-client.example.com', 'service-a.internal'];
  if (!allowedCNs.includes(cert.subject.CN)) {
    return res.status(403).json({ error: 'Certificate CN not authorized' });
  }

  // Validate certificate is not expiring soon (30 days warning)
  const expiryDate = new Date(cert.valid_to);
  const daysUntilExpiry = (expiryDate - new Date()) / (1000 * 60 * 60 * 24);

  if (daysUntilExpiry < 30) {
    console.warn(`Certificate for ${cert.subject.CN} expires in ${daysUntilExpiry.toFixed(0)} days`);
  }

  // Attach certificate info to request for auditing
  req.clientCert = {
    cn: cert.subject.CN,
    issuer: cert.issuer.CN,
    validFrom: cert.valid_from,
    validTo: cert.valid_to,
    fingerprint: cert.fingerprint
  };

  next();
});

// Protected API endpoint
app.get('/api/secure-data', (req, res) => {
  res.json({
    message: 'Secure data',
    authenticatedClient: req.clientCert.cn,
    timestamp: new Date().toISOString()
  });
});

// Create HTTPS server with mTLS
const server = https.createServer(serverOptions, app);

server.listen(8443, () => {
  console.log('🔒 Secure server running on https://localhost:8443');
  console.log('✓ Mutual TLS enabled');
  console.log('✓ Client certificate validation enforced');
});

// Handle TLS errors
server.on('tlsClientError', (err, tlsSocket) => {
  console.error('TLS Client Error:', err.message);
  // Log for security monitoring
  if (err.code === 'ECONNRESET' || err.code === 'UNABLE_TO_VERIFY_LEAF_SIGNATURE') {
    console.warn('Potential MITM attack detected - invalid certificate presented');
  }
});

// Example: Making outbound HTTPS requests with certificate validation
const axios = require('axios');
const httpsAgent = new https.Agent({
  ca: fs.readFileSync(path.join(__dirname, 'certs', 'ca-cert.pem')),
  cert: fs.readFileSync(path.join(__dirname, 'certs', 'client-cert.pem')),
  key: fs.readFileSync(path.join(__dirname, 'certs', 'client-key.pem')),
  rejectUnauthorized: true, // CRITICAL: Never disable
  checkServerIdentity: (hostname, cert) => {
    // Custom hostname validation
    const tls = require('tls');
    const err = tls.checkServerIdentity(hostname, cert);
    if (err) {
      console.error(`Hostname verification failed for ${hostname}:`, err.message);
      return err;
    }
    return undefined;
  }
});

async function callSecureAPI() {
  try {
    const response = await axios.get('https://api.example.com/data', {
      httpsAgent,
      timeout: 5000
    });
    return response.data;
  } catch (error) {
    if (error.code === 'CERT_HAS_EXPIRED') {
      console.error('Server certificate has expired');
    } else if (error.code === 'UNABLE_TO_VERIFY_LEAF_SIGNATURE') {
      console.error('Cannot verify server certificate signature');
    } else if (error.code === 'DEPTH_ZERO_SELF_SIGNED_CERT') {
      console.error('Self-signed certificate rejected');
    }
    throw error;
  }
}

import org.springframework.boot.web.client.RestTemplateBuilder;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.client.ClientHttpRequestFactory;
import org.springframework.http.client.SimpleClientHttpRequestFactory;
import org.springframework.web.client.RestTemplate;

import javax.net.ssl.*;
import java.io.FileInputStream;
import java.io.IOException;
import java.security.*;
import java.security.cert.Certificate;
import java.security.cert.CertificateException;
import java.security.cert.X509Certificate;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

@Configuration
public class SecureRestTemplateConfig {

    // Pinned certificate fingerprints (SHA-256) - update when rotating certificates
    private static final Set<String> PINNED_CERTIFICATES = new HashSet<>(Arrays.asList(
        "E3:B0:C4:42:98:FC:1C:14:9A:FB:F4:C8:99:6F:B9:24:27:AE:41:E4:64:9B:93:4C:A4:95:99:1B:78:52:B8:55",
        "2C:F4:27:02:A7:8F:D9:5C:3E:9D:1C:7A:6B:4E:8F:2D:3A:1B:9C:4E:5F:6A:7B:8C:9D:0E:1F:2A:3B:4C:5D:6E"
    ));

    @Bean
    public RestTemplate secureRestTemplate(RestTemplateBuilder builder) throws Exception {
        return builder
            .requestFactory(this::createSecureRequestFactory)
            .build();
    }

    private ClientHttpRequestFactory createSecureRequestFactory() throws Exception {
        // Load truststore with CA certificates
        KeyStore trustStore = KeyStore.getInstance("JKS");
        try (FileInputStream trustStoreFile = new FileInputStream("/etc/ssl/truststore.jks")) {
            trustStore.load(trustStoreFile, "changeit".toCharArray());
        }

        // Load keystore with client certificate for mTLS
        KeyStore keyStore = KeyStore.getInstance("JKS");
        try (FileInputStream keyStoreFile = new FileInputStream("/etc/ssl/keystore.jks")) {
            keyStore.load(keyStoreFile, "changeit".toCharArray());
        }

        // Initialize TrustManager with certificate pinning
        TrustManagerFactory tmf = TrustManagerFactory.getInstance(TrustManagerFactory.getDefaultAlgorithm());
        tmf.init(trustStore);

        // Create custom TrustManager with certificate pinning
        X509TrustManager defaultTrustManager = (X509TrustManager) tmf.getTrustManagers()[0];
        X509TrustManager pinningTrustManager = new X509TrustManager() {
            @Override
            public void checkClientTrusted(X509Certificate[] chain, String authType) throws CertificateException {
                defaultTrustManager.checkClientTrusted(chain, authType);
            }

            @Override
            public void checkServerTrusted(X509Certificate[] chain, String authType) throws CertificateException {
                // First, perform default certificate validation
                defaultTrustManager.checkServerTrusted(chain, authType);

                // Then, check certificate pinning
                boolean pinMatched = false;
                for (X509Certificate cert : chain) {
                    try {
                        MessageDigest md = MessageDigest.getInstance("SHA-256");
                        byte[] publicKeyHash = md.digest(cert.getPublicKey().getEncoded());
                        String fingerprint = bytesToHex(publicKeyHash);

                        if (PINNED_CERTIFICATES.contains(fingerprint)) {
                            pinMatched = true;
                            break;
                        }
                    } catch (NoSuchAlgorithmException e) {
                        throw new CertificateException("Failed to compute certificate fingerprint", e);
                    }
                }

                if (!pinMatched) {
                    throw new CertificateException(
                        "Certificate pinning validation failed. " +
                        "Server certificate does not match any pinned certificates. " +
                        "Possible MITM attack detected."
                    );
                }
            }

            @Override
            public X509Certificate[] getAcceptedIssuers() {
                return defaultTrustManager.getAcceptedIssuers();
            }
        };

        // Initialize KeyManager for client certificate authentication
        KeyManagerFactory kmf = KeyManagerFactory.getInstance(KeyManagerFactory.getDefaultAlgorithm());
        kmf.init(keyStore, "changeit".toCharArray());

        // Create SSL context with custom trust manager
        SSLContext sslContext = SSLContext.getInstance("TLSv1.3");
        sslContext.init(kmf.getKeyManagers(), new TrustManager[]{pinningTrustManager}, new SecureRandom());

        // Configure HTTPS connection factory
        SimpleClientHttpRequestFactory requestFactory = new SimpleClientHttpRequestFactory() {
            @Override
            protected void prepareConnection(HttpURLConnection connection, String httpMethod) throws IOException {
                if (connection instanceof HttpsURLConnection) {
                    HttpsURLConnection httpsConnection = (HttpsURLConnection) connection;
                    httpsConnection.setSSLSocketFactory(sslContext.getSocketFactory());

                    // Enable strict hostname verification
                    httpsConnection.setHostnameVerifier((hostname, session) -> {
                        // Use default hostname verifier
                        HostnameVerifier defaultVerifier = HttpsURLConnection.getDefaultHostnameVerifier();
                        return defaultVerifier.verify(hostname, session);
                    });
                }
                super.prepareConnection(connection, httpMethod);
            }
        };

        requestFactory.setConnectTimeout(5000);
        requestFactory.setReadTimeout(5000);

        return requestFactory;
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < bytes.length; i++) {
            sb.append(String.format("%02X", bytes[i]));
            if (i < bytes.length - 1) {
                sb.append(":");
            }
        }
        return sb.toString();
    }
}

// Example usage in a service
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestTemplate;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;

@Slf4j
@Service
@RequiredArgsConstructor
public class SecureApiService {

    private final RestTemplate secureRestTemplate;

    public String callSecureEndpoint() {
        try {
            String response = secureRestTemplate.getForObject(
                "https://api.example.com/secure-endpoint",
                String.class
            );
            log.info("Secure API call successful");
            return response;
        } catch (Exception e) {
            log.error("Secure API call failed: {}", e.getMessage());
            if (e.getCause() instanceof CertificateException) {
                log.error("SECURITY ALERT: Certificate validation failed - possible MITM attack");
            }
            throw e;
        }
    }
}

